import React from "react";
import { Box, Grid, Typography, Link, IconButton } from '@mui/material';
import GitHubIcon from '@mui/icons-material/GitHub';
import FacebookIcon from '@mui/icons-material/Facebook';
import InstagramIcon from '@mui/icons-material/Instagram';
import LanguageIcon from '@mui/icons-material/Language';
import LinkedInIcon from '@mui/icons-material/LinkedIn';

const Footer = () => {
    return (
        <Box component='footer' sx={{ backgroundColor: '#1A202C', padding: 5, marginTop: 2,}}>
            <Grid container spacing={2}>
                <Grid item xs={12} sm={4}>
                    <img src="" alt="logo" style={{ height: 30 }} />
                    <Box>
                        <IconButton component="a" href="https://www.facebook.com" target="_blank" aria-label="Facebook">
                            <FacebookIcon />
                        </IconButton>
                        <IconButton component="a" href="https://www.instagram.com" target="_blank" aria-label="Instagram">
                            <InstagramIcon />
                        </IconButton>
                        <IconButton component="a" href="https://www.linkedin.com" target="_blank" aria-label="LinkedIn">
                            <LinkedInIcon />
                        </IconButton>
                        <IconButton component="a" href="https://yourlabwebsite.com" target="_blank" aria-label="Lab Website">
                            <LanguageIcon />
                        </IconButton>
                    </Box>
                </Grid>
            </Grid>

        </Box>
    );
};

export default Footer;
